def fib_word(L):
    s = [0]
    while len(s) < L:
        s = sum(([0, 1] if c == 0 else [0] for c in s), [])
    return s[:L]
def T(w):
    N = len(w)
    v = [i for i, b in enumerate(w) if b == 0]
    u = [i for i, b in enumerate(w) if b == 1]
    wp = [None] * N
    wp[0] = 0
    for k in range(N):
        if wp[k] is None: break
        if k < len(v) and v[k] < N: wp[v[k]] = wp[k]
        if k < len(u) and u[k] < N: wp[u[k]] = 1 - wp[k]
    return wp
